query:
UPDATE products p
JOIN (
  SELECT c1.id as old_id, MIN(c2.id) as new_id
  FROM categories c1
  JOIN categories c2 ON c1.name = c2.name
  WHERE c1.id > c2.id
  GROUP BY c1.id
) mapping ON p.categoryId = mapping.old_id
SET p.categoryId = mapping.new_id;

DELETE FROM categories WHERE id NOT IN (
  SELECT MIN(id) FROM (
    SELECT MIN(id) as id FROM categories GROUP BY name
  ) t
);

